declare(strict_types=1);require_once __DIR__.'/../../config/config.php';require_once ROOT_PATH.'/functions/maintenance_functions.php';requireAuth();enforceModuleAccess('maintenance');$status=(string)($_GET['status']??'');$where='m.deleted_at IS NULL';$params=[];if($status!==''){$where.=' AND m.status=?';$params[]=$status;}$s=getDb()->prepare("SELECT m.*,v.registration_number FROM maintenance_logs m JOIN vehicles v ON v.id=m.vehicle_id WHERE $where ORDER BY m.scheduled_date DESC");$s->execute($params);$rows=$s->fetchAll();$summary=maintenanceSummary();$pageTitle='Maintenance';require ROOT_PATH.'/includes/header.php';require ROOT_PATH.'/includes/sidebar.php';
?><main class="main-content maintenance-module"><?php require ROOT_PATH.'/includes/navbar.php';?><section class="page-heading page-section"><div><h1 class="page-title">Maintenance operations</h1><p class="page-subtitle">Plan work, protect fleet availability, and control maintenance cost.</p></div><div class="d-flex gap-2"><a class="btn btn-secondary" href="calendar.php">Calendar</a><a class="btn btn-primary" href="add.php">Schedule maintenance</a></div></section><section class="grid grid-4 maintenance-kpis page-section"><?php foreach(['Scheduled'=>$summary['scheduled'],'In progress'=>$summary['active'],'Completed'=>$summary['completed'],'Total cost'=>formatCurrency((float)$summary['total_cost'])] as $label=>$value):?><article class="card maintenance-kpi"><small><?=e($label)?></small><strong><?=e((string)$value)?></strong></article><?php endforeach;?></section><section class="card table-card"><form class="maintenance-toolbar"><select name="status"><option value="">All statuses</option><?php foreach(['Scheduled','In Progress','Completed','Cancelled'] as $item):?><option<?=$status===$item?' selected':''?>><?=$item?></option><?php endforeach;?></select><button class="btn btn-secondary">Filter</button><a class="btn btn-outline" href="<?=e(siteUrl('ajax/maintenance_export.php'))?>">CSV export</a></form><div class="table-responsive"><table class="maintenance-table"><thead><tr><th>Maintenance ID</th><th>Vehicle</th><th>Type</th><th>Priority</th><th>Workshop / mechanic</th><th>Cost</th><th>Scheduled</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($rows as $row):?><tr><td><?=e($row['maintenance_code']?:'#'.$row['id'])?></td><td><?=e($row['registration_number'])?></td><td><?=e($row['maintenance_type'])?></td><td><span class="badge badge-<?=$row['priority']==='Critical'?'danger':($row['priority']==='High'?'warning':'secondary')?>"><?=e($row['priority'])?></span></td><td><?=e($row['vendor_name']?:'—')?><small><?=e($row['mechanic_name']?:'')?></small></td><td><?=e(formatCurrency((float)$row['cost']))?></td><td><?=e(formatDate($row['scheduled_date']))?></td><td><span class="badge badge-<?=$row['status']==='Completed'?'success':($row['status']==='In Progress'?'info':'warning')?>"><?=e($row['status'])?></span></td><td><a href="view.php?id=<?=$row['id']?>"><i class="fa fa-eye"></i></a> <a href="edit.php?id=<?=$row['id']?>"><i class="fa fa-pencil"></i></a></td></tr><?php endforeach;?></tbody></table></div></section></main><?php require ROOT_PATH.'/includes/footer.php';?>
